UPDATE public.questions SET
  stimulus_text = 'The following sentence is from a novel about a group of friends who spend a summer together at a lake house. "The friends loved to swim,  hike, and play games, but they also enjoyed relaxing and talking  in the evenings." Which choice provides the best way to punctuate the sentence? Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
  question_text = 'Which choice provides the best way to punctuate the sentence?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The friends loved to swim, hike, and play games, but they also enjoyed relaxing and talking in the evenings.","is_correct":true,"explanation":"The sentence contains two independent clauses, joined by the coordinating conjunction \"but.\" The most appropriate way to punctuate this sentence is to separate the two clauses with a comma. The other punctuation choices create either a comma splice (Choice B) or a sentence fragment (Choice C), both. Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The friends loved to swim, hike, and play games; but they also enjoyed relaxing and talking in the evenings.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The friends loved to swim, hike, and play games, but they also enjoyed relaxing and talking, in the evenings.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The friends loved to swim, hike, and play games; but, they also enjoyed relaxing and talking in the evenings.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The sentence contains two independent clauses, joined by the coordinating conjunction "but." The most appropriate way to punctuate this sentence is to separate the two clauses with a comma. The other punctuation choices create either a comma splice (Choice B) or a sentence fragment (Choice C), both of which are grammatical errors. Choice D is incorrect because the comma before the conjunction "but" isn''t necessary in this sentence. The passage states that "The following sentence is from a novel about a group of friends who spend a summer together at a lake house. "The friend…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: The friends loved to swim, hike, and play games, but they also enjoyed relaxing and talking in the e…. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
